// Copyright (C) 2019 ProtonTech AGpackage packetimport ("io""github.com/ProtonMail/go-crypto/openpgp/errors""github.com/ProtonMail/go-crypto/openpgp/internal/algorithm")// AEADEncrypted represents an AEAD Encrypted Packet.// See https://www.ietf.org/archive/id/draft-koch-openpgp-2015-rfc4880bis-00.html#name-aead-encrypted-data-packet-ttype AEADEncrypted struct {cipher        Ciphermode          AEADModechunkSizeByte byteContents      io.Reader // Encrypted chunks and tagsinitialNonce  []byte    // Referred to as IV in RFC4880-bis}// Only currently defined versionconst aeadEncryptedVersion = 1 *AEADEncrypted) parse(buf io.Reader) error {headerData := make([]byte, 4)if n, err := io.ReadFull(buf, headerData); n < 4 {return errors.AEADError("could not read aead header:" + err.Error())}// Read initial noncemode := AEADMode(headerData[2])nonceLen := mode.IvLength()// This packet supports only EAX and OCB// https://www.ietf.org/archive/id/draft-koch-openpgp-2015-rfc4880bis-00.html#name-aead-encrypted-data-packet-tif nonceLen == 0 || mode > AEADModeOCB {return errors.AEADError("unknown mode")}initialNonce := make([]byte, nonceLen)if n, err := io.ReadFull(buf, initialNonce); n < nonceLen {return errors.AEADError("could not read aead nonce:" + err.Error())}ae.Contents = bufae.initialNonce = initialNoncec := headerData[1]if _, ok := algorithm.CipherById[c]; !ok {return errors.UnsupportedError("unknown cipher: " + string(c))}ae.cipher = Cipher(c)ae.mode = modeae.chunkSizeByte = headerData[3]return nil}// Decrypt returns a io.ReadCloser from which decrypted bytes can be read, or// an error. *AEADEncrypted) Decrypt(ciph Cipher, key []byte) (io.ReadCloser, error) {return ae.decrypt(key)}// decrypt prepares an aeadCrypter and returns a ReadCloser from which// decrypted bytes can be read (see aeadDecrypter.Read()). *AEADEncrypted) decrypt(key []byte) (io.ReadCloser, error) {blockCipher := ae.cipher.new(key)aead := ae.mode.new(blockCipher)// Carry the first tagLen bytestagLen := ae.mode.TagLength()peekedBytes := make([]byte, tagLen)n, err := io.ReadFull(ae.Contents, peekedBytes)if n < tagLen || (err != nil && err != io.EOF) {return nil, errors.AEADError("Not enough data to decrypt:" + err.Error())}chunkSize := decodeAEADChunkSize(ae.chunkSizeByte)return &aeadDecrypter{aeadCrypter: aeadCrypter{aead:           aead,chunkSize:      chunkSize,initialNonce:   ae.initialNonce,associatedData: ae.associatedData(),chunkIndex:     make([]byte, 8),packetTag:      packetTypeAEADEncrypted,},reader:      ae.Contents,peekedBytes: peekedBytes}, nil}// associatedData for chunks: tag, version, cipher, mode, chunk size byte *AEADEncrypted) associatedData() []byte {return []byte{0xD4,aeadEncryptedVersion,byte(ae.cipher),byte(ae.mode),ae.chunkSizeByte}}